import itertools
import math
from pandas import Series

def task_func(elements, subset_size, top_n=2):
    if subset_size > len(elements):
        return (1, Series())

    power = math.factorial(len(elements))
    combinations = power // (math.factorial(len(elements) - subset_size) * math.factorial(subset_size))
    product_of_sums = 1
    top_n_sums_series = Series()

    for combination in itertools.combinations(elements, subset_size):
        sum_of_subset = sum(combination)
        product_of_sums *= sum_of_subset
        top_n_sums_series = top_n_sums_series.append({f"sum_{len(top_n_sums_series)}": sum_of_subset}, ignore_index=True)
        if len(top_n_sums_series) > top_n:
            top_n_sums_series = top_n_sums_series.sort_values(ascending=False).head(top_n)
            break

    return (product_of_sums, top_n_sums_series)
